const fs = require('fs');
const path = require('path');
const { faker } = require('@faker-js/faker');

// Number of users to generate (override with: node generate-users.js 50)
const COUNT = Number(process.argv[2]) || 10;

const DATA_DIR = path.join(__dirname, 'data');

// CSV-escape a single value: wrap in quotes and double any inner quotes.
function csvEscape(value) {
  const str = String(value ?? '');
  return `"${str.replace(/"/g, '""')}"`;
}

function generateUser() {
  const firstName = faker.person.firstName();
  const lastName = faker.person.lastName();
  return {
    id: faker.string.uuid(),
    firstName,
    lastName,
    email: faker.internet.email({ firstName, lastName }),
    phone: faker.phone.number(),
    city: faker.location.city(),
    country: faker.location.country(),
    company: faker.company.name(),
    jobTitle: faker.person.jobTitle(),
    signupDate: faker.date.past({ years: 2 }).toISOString().slice(0, 10),
  };
}

const users = Array.from({ length: COUNT }, generateUser);

const headers = Object.keys(users[0]);
const rows = users.map((user) =>
  headers.map((key) => csvEscape(user[key])).join(',')
);
const csv = [headers.join(','), ...rows].join('\n') + '\n';

fs.mkdirSync(DATA_DIR, { recursive: true });
const outPath = path.join(DATA_DIR, 'users.csv');
fs.writeFileSync(outPath, csv);

console.log(`Generated ${COUNT} users -> ${path.relative(__dirname, outPath)}`);

