node -e '
const fs=require("fs");
const parse=f=>fs.readFileSync("data/"+f,"utf8").trim().split("\n").slice(1).map(l=>l.split(","));
const M=parse("merchants.csv"), S=parse("subscribers.csv"), O=parse("orders.csv");
const mid=new Set(M.map(r=>r[0]));
const subId=new Set(S.map(r=>r[0]));
const subPhones=new Set(S.map(r=>r[2]));
// uniqueness
console.log("merchant ids unique:", mid.size===M.length);
console.log("merchant domains unique:", new Set(M.map(r=>r[1])).size===M.length);
console.log("subscriber ids unique:", subId.size===S.length);
// per-merchant phone uniqueness
const perM={}; let dup=0;
S.forEach(r=>{const k=r[1]+"|"+r[2]; if(perM[k])dup++; perM[k]=1;});
console.log("per-merchant phone dups:", dup);
// FK integrity
console.log("sub merchant FK ok:", S.every(r=>mid.has(r[1])));
console.log("order merchant FK ok:", O.every(r=>mid.has(r[1])));
console.log("order subscriber FK ok:", O.every(r=>r[2]===""||subId.has(r[2])));
console.log("order email present:", O.every(r=>r[3]&&r[3].includes("@")));
console.log("order created_at present:", O.every(r=>r[5]));
// unsub rate
const unsub=S.filter(r=>r[4]!=="").length;
console.log("unsub rate:", (100*unsub/S.length).toFixed(1)+"% (>=5%)");
// phone coverage + overlap
const withPhone=O.filter(r=>r[4]!=="");
const overlap=withPhone.filter(r=>subPhones.has(r[4]));
console.log("orders w/ phone:", (100*withPhone.length/O.length).toFixed(1)+"% (>=30%)");
console.log("of those overlapping subs:", overlap.length+"/"+withPhone.length);
// unsubscribed_at after subscribed_at
console.log("unsub after sub:", S.filter(r=>r[4]!=="").every(r=>new Date(r[4])>=new Date(r[3])));
'

