function lines(f){return readline.createInterface({input:fs.createReadStream("data/"+f),crlfDelay:Infinity});}
(async()=>{
  const mids=new Set(); const domains=new Set(); let h=true;
  for await (const l of lines("merchants.csv")){ if(h){h=false;continue;} const [id,dom]=l.split(","); mids.add(id); domains.add(dom);}
  console.log("merchants:",mids.size,"| unique domains:",domains.size);

  const subIds=new Set(); const subPhones=new Set(); const perMerchant=new Set();
  let sCount=0,unsub=0,nullSubAt=0,fkBad=0,perMdup=0,unsubBefore=0; h=true;
  for await (const l of lines("subscribers.csv")){ if(h){h=false;continue;}
    const [id,mid,phone,subAt,unsubAt]=l.split(",");
    sCount++; subIds.add(id); subPhones.add(phone);
    const k=mid+"|"+phone; if(perMerchant.has(k))perMdup++; else perMerchant.add(k);
    if(!mids.has(mid))fkBad++; if(!subAt)nullSubAt++;
    if(unsubAt){unsub++; if(new Date(unsubAt)<new Date(subAt))unsubBefore++;}
  }
  console.log("subscribers:",sCount,"| unique ids:",subIds.size,"| FK bad:",fkBad,"| per-merchant phone dups:",perMdup,"| null subscribed_at:",nullSubAt);
  console.log("  unsubscribed:",unsub,"("+(100*unsub/sCount).toFixed(2)+"%, need >=5%) | unsub before sub:",unsubBefore);

  let oCount=0,oFkM=0,oFkS=0,noEmail=0,badEmail=0,noCreated=0,withPhone=0,phoneOverlap=0,nullSub=0; h=true;
  const oIds=new Set();
  for await (const l of lines("orders.csv")){ if(h){h=false;continue;}
    const [id,mid,sid,email,phone,createdAt]=l.split(",");
    oCount++; oIds.add(id);
    if(!mids.has(mid))oFkM++;
    if(sid===""){nullSub++;} else if(!subIds.has(sid))oFkS++;
    if(!email)noEmail++; else if(!email.includes("@"))badEmail++;
    if(!createdAt)noCreated++;
    if(phone){withPhone++; if(subPhones.has(phone))phoneOverlap++;}
  }
  console.log("orders:",oCount,"| unique ids:",oIds.size,"| merchant FK bad:",oFkM,"| subscriber FK bad:",oFkS,"| null subscriber_id:",nullSub);
  console.log("  no email:",noEmail,"| invalid email:",badEmail,"| no created_at:",noCreated);
  console.log("  orders w/ phone:",withPhone,"("+(100*withPhone/oCount).toFixed(2)+"%, need >=30%) | overlapping subscriber phones:",phoneOverlap);
})();
'
